use std::fs;

use axum::{
    extract::State,
    routing::{get, post},
    Json, Router,
};
use serde::Deserialize;
use serde_json::Value;

use crate::role_mailbox::{
    AddTranscriptionLinkRequest, CreateRoleMailboxMessageRequest, RoleId, RoleMailbox,
    RoleMailboxContext, RoleMailboxMessage, RoleMailboxMessageType, TranscriptionLink,
};
use crate::runtime_governance::RuntimeGovernancePaths;
use crate::AppState;

#[derive(Debug, Deserialize)]
pub struct CreateMessageApiRequest {
    pub thread_id: Option<String>,
    pub thread_subject: Option<String>,
    pub thread_participants: Option<Vec<RoleId>>,
    pub context: RoleMailboxContext,
    pub from_role: RoleId,
    pub to_roles: Vec<RoleId>,
    pub message_type: RoleMailboxMessageType,
    pub body: String,
    pub attachments: Vec<crate::ace::ArtifactHandle>,
    pub relates_to_message_id: Option<String>,
    pub transcription_links: Vec<TranscriptionLink>,
    pub idempotency_key: String,
}

#[derive(Debug, Deserialize)]
pub struct AddTranscriptionApiRequest {
    pub thread_id: String,
    pub message_id: String,
    pub link: TranscriptionLink,
}

pub fn routes(state: AppState) -> Router {
    Router::new()
        .route("/role_mailbox/index", get(read_index))
        .route("/role_mailbox/messages", post(create_message))
        .route("/role_mailbox/transcriptions", post(add_transcription_link))
        .with_state(state)
}

async fn read_index() -> Result<Json<Value>, String> {
    let runtime_paths = RuntimeGovernancePaths::resolve().map_err(|e| e.to_string())?;
    let index_path = runtime_paths.role_mailbox_export_dir().join("index.json");
    let raw = fs::read_to_string(&index_path).map_err(|e| e.to_string())?;
    let parsed: Value = serde_json::from_str(&raw).map_err(|e| e.to_string())?;
    Ok(Json(parsed))
}

async fn create_message(
    State(state): State<AppState>,
    Json(req): Json<CreateMessageApiRequest>,
) -> Result<Json<RoleMailboxMessage>, String> {
    let mailbox =
        RoleMailbox::new_for_repo(state.flight_recorder.clone()).map_err(|e| e.to_string())?;
    let internal = CreateRoleMailboxMessageRequest {
        thread_id: req.thread_id,
        thread_subject: req.thread_subject,
        thread_participants: req.thread_participants,
        context: req.context,
        from_role: req.from_role,
        to_roles: req.to_roles,
        message_type: req.message_type,
        body: req.body,
        attachments: req.attachments,
        relates_to_message_id: req.relates_to_message_id,
        transcription_links: req.transcription_links,
        idempotency_key: req.idempotency_key,
    };

    mailbox
        .create_message(internal)
        .await
        .map(Json)
        .map_err(|e| e.to_string())
}

async fn add_transcription_link(
    State(state): State<AppState>,
    Json(req): Json<AddTranscriptionApiRequest>,
) -> Result<Json<Value>, String> {
    let mailbox =
        RoleMailbox::new_for_repo(state.flight_recorder.clone()).map_err(|e| e.to_string())?;
    let internal = AddTranscriptionLinkRequest {
        thread_id: req.thread_id,
        message_id: req.message_id,
        link: req.link,
    };
    mailbox
        .add_transcription_link(internal)
        .await
        .map_err(|e| e.to_string())?;
    Ok(Json(serde_json::json!({ "ok": true })))
}

use super::types::TaskBoardStatus;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct TaskBoardEntry {
    pub wp_id: String,
    pub token: String,
    pub status: TaskBoardStatus,
}

#[derive(Debug, Clone, Default, PartialEq, Eq)]
pub struct TaskBoardSections {
    pub stub: Vec<TaskBoardEntry>,
    pub ready: Vec<TaskBoardEntry>,
    pub in_progress: Vec<TaskBoardEntry>,
    pub blocked: Vec<TaskBoardEntry>,
    pub gated: Vec<TaskBoardEntry>,
    pub done: Vec<TaskBoardEntry>,
    pub cancelled: Vec<TaskBoardEntry>,
}

impl TaskBoardSections {
    pub fn entries_for_status_mut(&mut self, status: TaskBoardStatus) -> &mut Vec<TaskBoardEntry> {
        match status {
            TaskBoardStatus::Unknown => &mut self.stub,
            TaskBoardStatus::Ready => &mut self.ready,
            TaskBoardStatus::InProgress => &mut self.in_progress,
            TaskBoardStatus::Blocked => &mut self.blocked,
            TaskBoardStatus::Gated => &mut self.gated,
            TaskBoardStatus::Done => &mut self.done,
            TaskBoardStatus::Cancelled => &mut self.cancelled,
        }
    }

    pub fn entries_for_status(&self, status: TaskBoardStatus) -> &Vec<TaskBoardEntry> {
        match status {
            TaskBoardStatus::Unknown => &self.stub,
            TaskBoardStatus::Ready => &self.ready,
            TaskBoardStatus::InProgress => &self.in_progress,
            TaskBoardStatus::Blocked => &self.blocked,
            TaskBoardStatus::Gated => &self.gated,
            TaskBoardStatus::Done => &self.done,
            TaskBoardStatus::Cancelled => &self.cancelled,
        }
    }
}

fn status_for_heading(heading: &str) -> Option<TaskBoardStatus> {
    let heading = heading.trim();
    let heading = heading.strip_prefix("## ")?;
    let title = heading.trim();

    if title.eq_ignore_ascii_case("Ready for Dev") {
        return Some(TaskBoardStatus::Ready);
    }
    if title.eq_ignore_ascii_case("In Progress") {
        return Some(TaskBoardStatus::InProgress);
    }
    if title.eq_ignore_ascii_case("Blocked") {
        return Some(TaskBoardStatus::Blocked);
    }
    if title.eq_ignore_ascii_case("Done") {
        return Some(TaskBoardStatus::Done);
    }
    if title.to_ascii_lowercase().starts_with("stub backlog") {
        return Some(TaskBoardStatus::Unknown);
    }
    if title.to_ascii_lowercase().starts_with("superseded") {
        return Some(TaskBoardStatus::Cancelled);
    }

    None
}

fn parse_entry_line(line: &str) -> Option<(String, String)> {
    let line = line.trim();
    if !line.starts_with("- **[") {
        return None;
    }
    let after_prefix = line.strip_prefix("- **[")?;
    let (wp_id, rest) = after_prefix.split_once("]**")?;
    let rest = rest.trim_start();
    let rest = rest.strip_prefix("-")?.trim_start();
    let token_part = rest.strip_prefix("[")?;
    let (token, _rest) = token_part.split_once(']')?;
    Some((wp_id.trim().to_string(), token.trim().to_string()))
}

pub fn parse_task_board(markdown: &str) -> TaskBoardSections {
    let mut sections = TaskBoardSections::default();
    let mut current: Option<TaskBoardStatus> = None;

    for raw_line in markdown.lines() {
        let line = raw_line.trim_end();
        if let Some(status) = status_for_heading(line) {
            current = Some(status);
            continue;
        }

        let Some(status) = current else { continue };
        let Some((wp_id, token)) = parse_entry_line(line) else {
            continue;
        };

        sections
            .entries_for_status_mut(status)
            .push(TaskBoardEntry {
                wp_id,
                token,
                status,
            });
    }

    sections
}

fn format_entry(entry: &TaskBoardEntry) -> String {
    format!("- **[{}]** - [{}]", entry.wp_id, entry.token)
}

#[derive(Debug, Clone, Copy)]
struct SectionWindow {
    status: TaskBoardStatus,
    start: usize,
}

fn find_section_windows(lines: &[String]) -> Vec<SectionWindow> {
    let mut headings: Vec<(usize, TaskBoardStatus)> = Vec::new();
    for (idx, line) in lines.iter().enumerate() {
        if let Some(status) = status_for_heading(line) {
            headings.push((idx, status));
        }
    }

    let mut windows: Vec<SectionWindow> = Vec::new();
    for (start, status) in headings {
        windows.push(SectionWindow { status, start });
    }
    windows
}

pub fn rewrite_task_board(markdown: &str, canonical: &TaskBoardSections) -> String {
    let mut lines: Vec<String> = markdown.lines().map(|l| l.to_string()).collect();

    let mut windows = find_section_windows(&lines);
    windows.sort_by(|a, b| b.start.cmp(&a.start));

    for window in windows {
        let mut end = lines.len();
        for i in (window.start + 1)..lines.len() {
            if lines[i].trim_start().starts_with("## ") {
                end = i;
                break;
            }
        }

        let mut entries: Vec<TaskBoardEntry> = canonical
            .entries_for_status(window.status)
            .iter()
            .cloned()
            .collect();
        entries.sort_by(|a, b| a.wp_id.cmp(&b.wp_id).then_with(|| a.token.cmp(&b.token)));
        let mut new_lines: Vec<String> = entries.iter().map(format_entry).collect();

        let mut insert_at = end;
        for i in (window.start + 1)..end {
            if parse_entry_line(&lines[i]).is_some() {
                insert_at = i;
                break;
            }
        }

        let mut i = window.start + 1;
        while i < end && i < lines.len() {
            if lines[i].trim_start().starts_with("## ") {
                break;
            }
            if parse_entry_line(&lines[i]).is_some() {
                lines.remove(i);
                end = end.saturating_sub(1);
                if i < insert_at {
                    insert_at = insert_at.saturating_sub(1);
                }
                continue;
            }
            i += 1;
        }

        if !new_lines.is_empty() && insert_at == end {
            if insert_at > 0 && !lines[insert_at.saturating_sub(1)].trim().is_empty() {
                new_lines.insert(0, String::new());
            }
        }

        lines.splice(insert_at..insert_at, new_lines);
    }

    let mut out = lines.join("\n");
    if !out.ends_with('\n') {
        out.push('\n');
    }
    out
}

use std::{
    io,
    path::{Component, Path, PathBuf},
};

use crate::storage::artifacts::resolve_workspace_root;

pub const RUNTIME_GOVERNANCE_ROOT_ENV: &str = "HANDSHAKE_GOVERNANCE_ROOT";
pub const RUNTIME_GOVERNANCE_DEFAULT_ROOT: &str = ".handshake/gov";
pub const RUNTIME_TASK_BOARD_FILE: &str = "TASK_BOARD.md";
pub const RUNTIME_SPEC_CURRENT_FILE: &str = "SPEC_CURRENT.md";
pub const RUNTIME_ROLE_MAILBOX_DIR: &str = "ROLE_MAILBOX";
pub const RUNTIME_GOVERNANCE_DECISIONS_DIR: &str = "governance_decisions";
pub const RUNTIME_GOVERNANCE_AUTO_SIGNATURES_DIR: &str = "auto_signatures";

#[derive(Debug, Clone)]
pub struct RuntimeGovernancePaths {
    workspace_root: PathBuf,
    governance_root: PathBuf,
}

impl RuntimeGovernancePaths {
    pub fn resolve() -> Result<Self, io::Error> {
        let workspace_root = resolve_workspace_root()
            .map_err(|err| io::Error::new(io::ErrorKind::Other, err.to_string()))?;
        let configured = std::env::var(RUNTIME_GOVERNANCE_ROOT_ENV)
            .ok()
            .map(|value| value.trim().to_string())
            .filter(|value| !value.is_empty())
            .map(PathBuf::from);
        Self::from_workspace_root_with_override(workspace_root, configured)
    }

    pub fn from_workspace_root(workspace_root: PathBuf) -> Result<Self, io::Error> {
        Self::from_workspace_root_with_override(workspace_root, None)
    }

    fn from_workspace_root_with_override(
        workspace_root: PathBuf,
        override_root: Option<PathBuf>,
    ) -> Result<Self, io::Error> {
        let workspace_root = absolutize(workspace_root)?;
        let configured =
            override_root.unwrap_or_else(|| PathBuf::from(RUNTIME_GOVERNANCE_DEFAULT_ROOT));
        if has_parent_dir(&configured) {
            return Err(io::Error::new(
                io::ErrorKind::InvalidInput,
                "runtime governance root must not contain '..' segments",
            ));
        }

        let governance_root = if configured.is_absolute() {
            configured
        } else {
            workspace_root.join(configured)
        };
        let governance_root = absolutize(governance_root)?;

        ensure_runtime_boundary(&workspace_root, &governance_root)?;

        Ok(Self {
            workspace_root,
            governance_root,
        })
    }

    pub fn workspace_root(&self) -> &Path {
        &self.workspace_root
    }

    pub fn governance_root(&self) -> &Path {
        &self.governance_root
    }

    pub fn governance_root_display(&self) -> String {
        ensure_trailing_slash(display_path(&self.workspace_root, &self.governance_root))
    }

    pub fn spec_current_path(&self) -> PathBuf {
        self.governance_root.join(RUNTIME_SPEC_CURRENT_FILE)
    }

    pub fn spec_current_display(&self) -> String {
        display_path(&self.workspace_root, &self.spec_current_path())
    }

    pub fn task_board_path(&self) -> PathBuf {
        self.governance_root.join(RUNTIME_TASK_BOARD_FILE)
    }

    pub fn task_board_display(&self) -> String {
        display_path(&self.workspace_root, &self.task_board_path())
    }

    pub fn role_mailbox_export_dir(&self) -> PathBuf {
        self.governance_root.join(RUNTIME_ROLE_MAILBOX_DIR)
    }

    pub fn role_mailbox_export_dir_display(&self) -> String {
        ensure_trailing_slash(display_path(
            &self.workspace_root,
            &self.role_mailbox_export_dir(),
        ))
    }

    pub fn governance_decisions_dir(&self) -> PathBuf {
        self.governance_root.join(RUNTIME_GOVERNANCE_DECISIONS_DIR)
    }

    pub fn governance_decisions_dir_display(&self) -> String {
